module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const parseP = (s) => { const m = String(s).trim().match(/^([\d.]+)\s*(%?)$/); if (!m) return NaN; const v = parseFloat(m[1]); return m[2] ? v / 100 : v; };
const showJoint = String(args.joint) !== 'false';
const percent = String(args.percent) === 'true';
let precN = parseInt(args.precision, 10); const prec = (precN >= 0 && precN <= 6) ? precN : 4;
let gapN = parseInt(args.gap, 10); const gap = (gapN >= 0 && gapN <= 80) ? gapN : 18;
const branches = [];
sections.map((s) => (s || '').trim()).filter(Boolean).forEach((s) => {
  const lines = s.split('\n').map((l) => l.trim()).filter(Boolean);
  if (!lines.length) return;
  const parse = (l) => { const i = l.lastIndexOf('|'); return i < 0 ? { label: l, p: NaN } : { label: l.slice(0, i).trim(), p: parseP(l.slice(i + 1)) }; };
  const head = parse(lines[0]);
  branches.push({ ...head, kids: lines.slice(1).map(parse) });
});
if (!branches.length) return `<div>(probtree: sections of "Label | p" lines)</div>`;
const fp = (p) => { if (!Number.isFinite(p)) return '?'; return percent ? (+(p * 100).toFixed(prec)).toString() + '%' : (+p.toFixed(prec)).toString(); };
let html = `\n\n<div class="mdp-mod-probtree" style="--pb-c:${args.color || 'var(--accent-color)'}; --pb-gap:${gap}px;">` +
  `<div class="mdp-pb-root">${esc(args.root || 'Start')}</div><div class="mdp-pb-l1">`;
branches.forEach((b) => {
  html += `<div class="mdp-pb-branch"><div class="mdp-pb-node"><span class="mdp-pb-p">${fp(b.p)}</span><span class="mdp-pb-lbl">${esc(b.label)}</span></div>`;
  if (b.kids.length) {
    html += `<div class="mdp-pb-l2">`;
    b.kids.forEach((k) => {
      const joint = Number.isFinite(b.p) && Number.isFinite(k.p) ? b.p * k.p : NaN;
      html += `<div class="mdp-pb-leaf"><span class="mdp-pb-p">${fp(k.p)}</span><span class="mdp-pb-lbl">${esc(k.label)}</span>` +
        (showJoint ? `<span class="mdp-pb-joint">${fp(joint)}</span>` : '') + `</div>`;
    });
    html += `</div>`;
  }
  html += `</div>`;
});
html += `</div></div>\n\n`;
return html;
